COMMIT;

-- =============================================================================
-- 21. VERIFICATION SELECTs (run after COMMIT)
--
-- Expected counts (left-hand label = entity, right-hand value = expected n):
--   schools           : 2
--   admins            : 2
--   teachers          : 7
--   parents           : 11
--   students          : 26
--   children          : 15
--   assignments       : 11
--   attendance        : 650
--   assessments       : 11
--   marks             : 42
--   exam_results      : 42
--   homework          : 11
--   fees              : 45
--   announcements     : 6
--   scholarships      : 3
--   scholarship_apps  : 4
--
-- All multi-tenancy 'bad' counts at the end must be 0.
-- =============================================================================
SELECT 'schools'         AS entity, count(*) AS n FROM schools WHERE slug IN ('sunrise-public-school','greenfield-academy')
UNION ALL SELECT 'admins',          count(*) FROM app_users WHERE role='school_admin'
UNION ALL SELECT 'teachers',        count(*) FROM app_users WHERE role='teacher'
UNION ALL SELECT 'parents',         count(*) FROM app_users WHERE role='parent'
UNION ALL SELECT 'students',        count(*) FROM students
UNION ALL SELECT 'children',        count(*) FROM children
UNION ALL SELECT 'assignments',     count(*) FROM teacher_subject_assignments
UNION ALL SELECT 'attendance',      count(*) FROM attendance_records
UNION ALL SELECT 'assessments',     count(*) FROM assessments
UNION ALL SELECT 'marks',           count(*) FROM assessment_marks
UNION ALL SELECT 'exam_results',    count(*) FROM exam_results
UNION ALL SELECT 'homework',        count(*) FROM homework
UNION ALL SELECT 'fees',            count(*) FROM fee_records
UNION ALL SELECT 'announcements',   count(*) FROM announcements
UNION ALL SELECT 'scholarships',    count(*) FROM scholarships
UNION ALL SELECT 'scholarship_apps',count(*) FROM scholarship_applications
ORDER BY entity;

-- MULTI-TENANCY ASSERTIONS — every 'bad' count below must be 0.
--   * parents must NOT carry a school_id (their tenancy is via children.school_id)
--   * every seeded child must carry a school_id
SELECT 'orphan_parents_with_school' AS check_name, count(*) AS bad
  FROM app_users WHERE role='parent' AND school_id IS NOT NULL
UNION ALL
SELECT 'children_without_school', count(*)
  FROM children WHERE school_id IS NULL;

-- CROSS-SCHOOL LEAK ASSERTION — must return 0.
--   A child's school_id must equal the canonical student's school_id.
SELECT count(*) AS mismatched_child_school
  FROM children c JOIN students s ON s.student_code = c.student_code
  WHERE c.school_id <> s.school_id;

